function esc(s) {
  if (s == null) return '';
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

const COL = ['A','B','C','D','E','F','G','H','I','J','K'];

function sheet(rows, frozenRow = 1) {
  const widths = rows[0].map((_, ci) =>
    Math.min(80, Math.max(12, ...rows.map(r => String(r[ci] || '').length * 0.9)))
  );

  let x = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>`;
  x += `<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main"`;
  x += ` xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">`;
  x += `<sheetViews><sheetView tabSelected="0" workbookViewId="0">`;
  x += `<pane ySplit="${frozenRow}" topLeftCell="A${frozenRow+1}" activePane="bottomLeft" state="frozen"/>`;
  x += `</sheetView></sheetViews>`;
  x += `<sheetFormatPr defaultRowHeight="15"/>`;
  x += `<cols>` + widths.map((w,i) =>
    `<col min="${i+1}" max="${i+1}" width="${w}" customWidth="1"/>`).join('') + `</cols>`;
  x += `<sheetData>`;
  rows.forEach((row, ri) => {
    const rn = ri + 1;
    const isHdr = ri === 0;
    const ht = isHdr ? 22 : 90;
    x += `<row r="${rn}" ht="${ht}" customHeight="1">`;
    row.forEach((cell, ci) => {
      const ref = `${COL[ci]}${rn}`;
      const s = isHdr ? 1 : (typeof cell === 'number' ? 3 : 2);
      x += `<c r="${ref}" t="inlineStr" s="${s}"><is><t>${esc(cell)}</t></is></c>`;
    });
    x += `</row>`;
  });
  x += `</sheetData><pageSetup orientation="landscape"/></worksheet>`;
  return x;
}

